def get_quiz_for_language(topic: str, lang: str = "it"):
    """Get quiz in specified language, fallback to Italian"""
    lang_quizzes = MULTILINGUAL_QUIZZES.get(lang, MULTILINGUAL_QUIZZES["it"])
    
    # Try exact topic match
    if topic in lang_quizzes:
        return lang_quizzes[topic]
    
    # Fallback to Italian with same topic
    it_quizzes = MULTILINGUAL_QUIZZES.get("it", {})
    if topic in it_quizzes:
        return it_quizzes[topic]
    
    return None

def get_all_topics_for_language(lang: str = "it"):
    """Get all available topics for a language"""
    lang_quizzes = MULTILINGUAL_QUIZZES.get(lang, MULTILINGUAL_QUIZZES["it"])
    return [
        {"id": key, "title": quiz["title"], "description": quiz["description"], "questions_count": len(quiz["questions"])}
        for key, quiz in lang_quizzes.items()
    ]
